@import "../props.media.css";

:where(html) {
  color-scheme: light;

  --link: var(--indigo-7);
  --link-visited: var(--purple-7);

  --text-1: var(--gray-12);
  --text-2: var(--gray-7);

  --surface-1: var(--gray-0);
  --surface-2: var(--gray-2);
  --surface-3: var(--gray-3);
  --surface-4: var(--gray-4);

  --scrollthumb-color: var(--gray-7);

  @media (--HDcolor) {
    @supports (color: color(display-p3 0 0 0)) {
      --link: color(display-p3 .1 .39 1);
      --link-visited: color(display-p3 .6 .2 1);
    }
  }

  & :where(dialog) {
    background-color: var(--surface-1);
  }

  & :where(button,.btn) {
    --_highlight: var(--_highlight-light);
    --_bg: var(--_bg-light);
    --_ink-shadow: var(--_ink-shadow-light);

    & :where([type="reset"]) {
      --_text: var(--red-6);
      --_border: var(--red-3);
    }
  }

  & :where(button,.btn,input:is([type="button"],[type="submit"],[type="reset"]))[disabled] {
    --_text: var(--gray-6);
  }

  & :where(textarea, select, input:not([type="button"],[type="submit"],[type="reset"])) {
    background-color: var(--surface-2);
  }
}

@mixin loading {
  .#{$prefix}--loading {
    @include component-reset.reset;
    @include animation.spin;

    block-size: $loading-size;

    inline-size: $loading-size;
  }

  // Animation (Spin by default)
  .#{$prefix}--loading__svg {
    fill: transparent;
  }

  .#{$prefix}--loading__svg circle {
    stroke-dasharray: $circumference $circumference;
    stroke-linecap: butt;
    stroke-width: 10;
  }

  .#{$prefix}--loading__stroke {
    stroke: $interactive;
    stroke-dashoffset: loading-progress($circumference, 81);
  }

  .#{$prefix}--loading--small .#{$prefix}--loading__stroke {
    stroke-dashoffset: loading-progress($circumference, 48);
  }

  .#{$prefix}--loading--stop {
    @include animation.stop;
  }

  .#{$prefix}--loading--small {
    block-size: convert.to-rem(16px);
    inline-size: convert.to-rem(16px);

    //See https://github.com/carbon-design-system/carbon/issues/13121
    line-height: 1rem;

    circle {
      stroke-width: 16;
    }
  }

  .#{$prefix}--loading--small .#{$prefix}--loading__svg {
    stroke: $interactive;
  }

  .#{$prefix}--loading__background {
    stroke: $layer-accent;
    stroke-dashoffset: -22;
  }
}

@keyframes skeleton-fade {
  0%,
  100% {
    opacity: 0.4;
  }

  50% {
    opacity: 1;
  }
}

.root {
  height: var(--skeleton-height, auto);
  width: var(--skeleton-width, 100%);
  border-radius: var(--skeleton-radius, var(--mantine-radius-default));
  position: relative;
  transform: translateZ(0);
  -webkit-transform: translateZ(0);

  &:where([data-animate])::after {
    animation: skeleton-fade 1500ms linear infinite;
  }

  &:where([data-visible]) {
    overflow: hidden;

    &::before {
      position: absolute;
      content: '';
      inset: 0;
      z-index: 10;
      background-color: var(--mantine-color-body);
    }

    &::after {
      position: absolute;
      content: '';
      inset: 0;
      z-index: 11;

      @mixin where-light {
        background-color: var(--mantine-color-gray-3);
      }

      @mixin where-dark {
        background-color: var(--mantine-color-dark-4);
      }
    }
  }
}

@layer components {
  .GhostButton {
    font-size: var(--font-size-13);
    color: var(--gray-t2);
    cursor: default;
    position: relative;
    z-index: 0;
    display: inline-flex;
    align-items: center;
    line-height: 1;
    gap: 0.375rem;
    height: 1.75rem;
    outline: 0;
    -webkit-user-select: none;
    user-select: none;
    border-radius: var(--radius-8);
    padding-inline: 0.5rem;

    &[data-layout='icon'] {
      width: 1.75rem;
      height: 1.75rem;
      justify-content: center;
      padding-inline: 0;
    }

    &:focus-visible {
      outline: 2px solid var(--gray-t2);
      outline-offset: -1px;
    }

    &:not(:focus-visible) {
      @media (hover: hover) {
        &:hover {
          background-color: var(--gray-c2);
        }
      }

      &[data-popup-open] {
        background-color: var(--gray-c2);
      }
    }
  }
}

@layer components {
  .SkipNav {
    clip: rect(0 0 0 0);
    clip-path: inset(50%);
    overflow: hidden;
    white-space: nowrap;
    border: 0;
    position: absolute;
    padding: 0;
    width: 1px;
    height: 1px;
    margin: -1px;

    &:focus-visible {
      clip: auto;
      clip-path: none;
      height: var(--header-height);
      overflow: visible;
      width: auto;
      white-space: normal;
      left: 0;
      z-index: 1;
      display: inline-flex;
      justify-content: center;
      align-items: center;
      padding-inline: 12px;
      background-color: var(--color-background);
      color: var(--color-blue);
      text-decoration: underline;
      text-underline-offset: 2px;
      text-decoration-thickness: 1px;
      text-decoration-color: color-mix(in oklab, var(--color-blue), transparent);
      outline: 2px solid var(--gray-t2);
      outline-offset: -2px;
      border-radius: var(--radius-4);
    }
  }
}

@import './theme.css';

.react-aria-Breadcrumbs {
  display: flex;
  align-items: center;
  list-style: none;
  margin: 0;
  padding: 0;
  color: var(--text-color);

  .react-aria-Breadcrumb {
    display: flex;
    align-items: center;
  }

  .react-aria-Link {
    font: var(--font-size) system-ui;
    color: var(--link-color-secondary);
    outline: none;
    position: relative;
    text-decoration: none;
    cursor: pointer;
    -webkit-tap-highlight-color: transparent;

    &[data-hovered],
    &[data-focus-visible] {
      text-decoration: underline;
    }

    &[data-current] {
      color: var(--text-color);
      font-weight: 600;
    }

    &[data-focus-visible] {
      border-radius: var(--radius-sm);
      outline: 2px solid var(--focus-ring-color);
    }

    &[data-disabled] {
      cursor: default;

      &:not([data-current]) {
        color: var(--text-color-disabled);
      }
    }
  }
}

@import './theme.css';
@import './utilities.css';

.react-aria-Button {
  border: none;
  border-radius: var(--radius);
  appearance: none;
  font: var(--font-size) system-ui;
  font-weight: 500;
  margin: 0;
  height: var(--spacing-8);
  padding: 0 var(--spacing-3);
  text-decoration: none;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--spacing-1);
  -webkit-tap-highlight-color: transparent;

  > svg {
    width: calc(var(--spacing) * 4.5);
    height: calc(var(--spacing) * 4.5);
  }

  &:has(> svg:only-child) {
    width: var(--spacing-8);
    flex-shrink: 0;
    padding: 0;
    border-radius: 9999px;
  }

  &[data-pressed] {
    scale: 0.95;
  }

  .react-aria-ProgressBar {
    @media (prefers-color-scheme: dark) {
      --highlight-background: var(--gray-1600);
    }
  }

  kbd {
    font: var(--font-size-sm) system-ui;
    background: var(--highlight-hover);
    border: 0.5px solid var(--tint-500);
    padding: 0 var(--spacing-1);
    border-radius: var(--radius-sm);
    margin-inline-start: var(--spacing-3);
  }
}

@import './theme.css';
@import './utilities.css';

.input-group {
  .react-aria-Group {
    display: flex;
    align-items: center;
    width: fit-content;
    padding: 0 var(--spacing-2);
    border-radius: var(--radius);
    font-size: var(--font-size);
    color: var(--field-text-color);
    overflow: hidden;
    height: 32px;

    &[data-focus-within] {
      outline: 2px solid var(--focus-ring-color);
      outline-offset: -1px;
    }

    &[data-disabled] {
      color: var(--text-color-disabled);
    }
  }

  .react-aria-Input {
    padding: var(--spacing-1);
    margin: 0;
    font: var(--font-size) system-ui;
    color: var(--text-color);
    outline: none;
    border: none;
    background: transparent;
    box-shadow: none;

    &:disabled {
      color: var(--text-color-disabled);
      &::placeholder {
        color: var(--text-color-disabled);
      }
    }

    &::placeholder {
      color: var(--text-color-placeholder);
      opacity: 1;
    }
  }
}

@import './theme.css';
@import './utilities.css';

.react-aria-Meter {
  display: grid;
  grid-template-areas:
    'label value'
    'bar bar';
  grid-template-columns: 1fr auto;
  width: 250px;
  color: var(--text-color);
  font: var(--font-size) system-ui;

  .value {
    grid-area: value;
  }

  .track {
    grid-area: bar;
    forced-color-adjust: none;
    height: calc(var(--spacing-2) + 2px);
    border-radius: 9999px;
    overflow: hidden;
  }

  .fill {
    --fill-color: var(--green);
    background: oklch(from var(--fill-color) var(--lightness-700) c h);
    height: calc(100% - 2px);
    margin: 1px 0 0 1px;
    border-radius: inherit;
    box-shadow:
      inset 0 1px 0 rgb(255 255 255 / 0.4),
      0 1px 0 lch(from var(--fill-color) 42% c h),
      0 0 0 1px var(--fill-color);

    @media (forced-colors: active) {
      box-shadow: none;
      background: Highlight;
    }
  }
}

@import './theme.css';
@import './utilities.css';

.segmented-control {
  display: flex;
  width: fit-content;
  border-radius: 9999px;

  .react-aria-SelectionIndicator {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    z-index: -1;
    transition-property: translate, width;
    transition-duration: 200ms;
    border-radius: 9999px;

    @media (prefers-reduced-motion: reduce) {
      transition: none;
    }
  }

  .segmented-control-item {
    all: unset;
    display: block;
    color: var(--gray-1200);
    font: var(--font-size) system-ui;
    font-weight: 500;
    height: var(--spacing-8);
    outline: none;
    padding: 0 var(--spacing-3);
    position: relative;
    z-index: 1;
    transition: color 200ms;
    -webkit-tap-highlight-color: transparent;

    span {
      display: inline-block;
      transition: scale 200ms;
    }

    &[data-pressed] span {
      scale: 0.9;
    }

    &[data-selected] {
      z-index: 0;
      color: var(--highlight-foreground);
    }

    &[data-focus-visible] {
      outline: 2px solid var(--focus-ring-color);
      outline-offset: 4px;
    }
  }
}

@import './theme.css';

.react-aria-Select {
  color: var(--text-color);
  position: relative;
  width: 200px;

  .react-aria-Button {
    --button-color: var(--gray);
    padding: 0 var(--spacing-2) 0 var(--spacing-3);
    width: 100%;
    min-width: 0;

    &[data-pressed] {
      scale: 1;
    }
  }

  .react-aria-SelectValue {
    flex: 1;
    text-align: start;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;

    &[data-placeholder] {
      color: var(--text-color-placeholder);
      font-weight: normal;
    }
  }

  .lucide-chevron-down {
    margin-inline-start: var(--spacing-2);
  }

  .react-aria-SelectValue {
    [slot='description'] {
      display: none;
    }
  }
}

.select-popover[data-trigger='Select'] {
  width: var(--trigger-width);
  padding: 0;
}

@import './theme.css';
@import './utilities.css';

.react-aria-TextField {
  display: flex;
  flex-direction: column;
}

.react-aria-Input,
.react-aria-TextArea {
  width: 100%;
  min-height: var(--spacing-8);
  padding: 0 var(--spacing-3);
  box-sizing: border-box;
  margin: 0;
  border: none;
  border-radius: var(--radius);
  font: var(--font-size) system-ui;
  color: var(--field-text-color);
  outline: none;
  -webkit-tap-highlight-color: transparent;

  &::placeholder {
    color: var(--text-color-placeholder);
  }

  &[data-focused] {
    outline: 2px solid var(--focus-ring-color);
    outline-offset: -1px;
  }

  &[data-disabled] {
    color: var(--text-color-disabled);
    &::placeholder {
      color: var(--text-color-disabled);
    }
  }
}

.react-aria-TextArea {
  min-height: 64px;
  padding: var(--spacing-2) var(--spacing-3);
}

@import './theme.css';
@import './utilities.css';

.react-aria-ToggleButton {
  border: none;
  forced-color-adjust: none;
  border-radius: var(--radius);
  appearance: none;
  vertical-align: middle;
  font: var(--font-size) system-ui;
  font-weight: 500;
  text-align: center;
  margin: 0;
  height: var(--spacing-8);
  padding: 0 var(--spacing-3);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  transition-property: background, box-shadow, text-shadow, scale;
  transition-duration: 200ms;
  -webkit-tap-highlight-color: transparent;

  > span {
    display: flex;
    align-items: center;
    justify-content: center;
  }

  > span > svg {
    width: var(--spacing-4);
    height: var(--spacing-4);
  }

  &:has(> span > svg:only-child) {
    width: var(--spacing-8);
    padding: 0;
    border-radius: 9999px;
  }

  &[data-pressed] {
    scale: 0.95;
  }
}

@keyframes bounce {
  from,
  20%,
  53%,
  to {
    animation-timing-function: cubic-bezier(0.215, 0.61, 0.355, 1);
    transform: translate3d(0, 0, 0);
  }

  40%,
  43% {
    animation-timing-function: cubic-bezier(0.755, 0.05, 0.855, 0.06);
    transform: translate3d(0, -30px, 0) scaleY(1.1);
  }

  70% {
    animation-timing-function: cubic-bezier(0.755, 0.05, 0.855, 0.06);
    transform: translate3d(0, -15px, 0) scaleY(1.05);
  }

  80% {
    transition-timing-function: cubic-bezier(0.215, 0.61, 0.355, 1);
    transform: translate3d(0, 0, 0) scaleY(0.95);
  }

  90% {
    transform: translate3d(0, -4px, 0) scaleY(1.02);
  }
}

.bounce {
  animation-name: bounce;
  transform-origin: center bottom;
}

@keyframes flash {
  from,
  50%,
  to {
    opacity: 1;
  }

  25%,
  75% {
    opacity: 0;
  }
}

.flash {
  animation-name: flash;
}

@keyframes flipInY {
  from {
    transform: perspective(400px) rotate3d(0, 1, 0, 90deg);
    animation-timing-function: ease-in;
    opacity: 0;
  }

  40% {
    transform: perspective(400px) rotate3d(0, 1, 0, -20deg);
    animation-timing-function: ease-in;
  }

  60% {
    transform: perspective(400px) rotate3d(0, 1, 0, 10deg);
    opacity: 1;
  }

  80% {
    transform: perspective(400px) rotate3d(0, 1, 0, -5deg);
  }

  to {
    transform: perspective(400px);
  }
}

.flipInY {
  backface-visibility: visible !important;
  animation-name: flipInY;
}

@keyframes flipOutX {
  from {
    transform: perspective(400px);
  }

  30% {
    transform: perspective(400px) rotate3d(1, 0, 0, -20deg);
    opacity: 1;
  }

  to {
    transform: perspective(400px) rotate3d(1, 0, 0, 90deg);
    opacity: 0;
  }
}

.flipOutX {
  animation-duration: calc(var(--animate-duration) * 0.75);
  animation-name: flipOutX;
  backface-visibility: visible !important;
}

@keyframes bounceInUp {
  from,
  60%,
  75%,
  90%,
  to {
    animation-timing-function: cubic-bezier(0.215, 0.61, 0.355, 1);
  }

  from {
    opacity: 0;
    transform: translate3d(0, 3000px, 0) scaleY(5);
  }

  60% {
    opacity: 1;
    transform: translate3d(0, -20px, 0) scaleY(0.9);
  }

  75% {
    transform: translate3d(0, 10px, 0) scaleY(0.95);
  }

  90% {
    transform: translate3d(0, -5px, 0) scaleY(0.985);
  }

  to {
    transform: translate3d(0, 0, 0);
  }
}

.bounceInUp {
  animation-name: bounceInUp;
}

@keyframes bounceOut {
  20% {
    transform: scale3d(0.9, 0.9, 0.9);
  }

  50%,
  55% {
    opacity: 1;
    transform: scale3d(1.1, 1.1, 1.1);
  }

  to {
    opacity: 0;
    transform: scale3d(0.3, 0.3, 0.3);
  }
}

.bounceOut {
  animation-duration: calc(var(--animate-duration) * 0.75);
  animation-name: bounceOut;
}

@keyframes slideInDown {
  from {
    transform: translate3d(0, -100%, 0);
    visibility: visible;
  }

  to {
    transform: translate3d(0, 0, 0);
  }
}

.slideInDown {
  animation-name: slideInDown;
}

@keyframes slideInLeft {
  from {
    transform: translate3d(-100%, 0, 0);
    visibility: visible;
  }

  to {
    transform: translate3d(0, 0, 0);
  }
}

.slideInLeft {
  animation-name: slideInLeft;
}

@keyframes slideInRight {
  from {
    transform: translate3d(100%, 0, 0);
    visibility: visible;
  }

  to {
    transform: translate3d(0, 0, 0);
  }
}

.slideInRight {
  animation-name: slideInRight;
}

@keyframes slideInUp {
  from {
    transform: translate3d(0, 100%, 0);
    visibility: visible;
  }

  to {
    transform: translate3d(0, 0, 0);
  }
}

.slideInUp {
  animation-name: slideInUp;
}

@keyframes slideOutDown {
  from {
    transform: translate3d(0, 0, 0);
  }

  to {
    visibility: hidden;
    transform: translate3d(0, 100%, 0);
  }
}

.slideOutDown {
  animation-name: slideOutDown;
}

@keyframes slideOutLeft {
  from {
    transform: translate3d(0, 0, 0);
  }

  to {
    visibility: hidden;
    transform: translate3d(-100%, 0, 0);
  }
}

.slideOutLeft {
  animation-name: slideOutLeft;
}

@keyframes slideOutRight {
  from {
    transform: translate3d(0, 0, 0);
  }

  to {
    visibility: hidden;
    transform: translate3d(100%, 0, 0);
  }
}

.slideOutRight {
  animation-name: slideOutRight;
}

@keyframes slideOutUp {
  from {
    transform: translate3d(0, 0, 0);
  }

  to {
    visibility: hidden;
    transform: translate3d(0, -100%, 0);
  }
}

.slideOutUp {
  animation-name: slideOutUp;
}

@import '@radix-ui/colors/amber.css';
@import '@radix-ui/colors/amber-dark.css';
@import '@radix-ui/colors/amber-alpha.css';
@import '@radix-ui/colors/amber-dark-alpha.css';

:root {
  --amber-contrast: #21201c; /* light mode sand 12 */
}

:root,
.light,
.light-theme {
  --amber-surface: #fefae4cc;
  --amber-indicator: var(--amber-9);
  --amber-track: var(--amber-9);
  @supports (color: color(display-p3 1 1 1)) {
    @media (color-gamut: p3) {
      --amber-surface: color(display-p3 0.9922 0.9843 0.902 / 0.8);
    }
  }
}

.dark,
.dark-theme {
  --amber-surface: #271f1380;
  --amber-indicator: var(--amber-9);
  --amber-track: var(--amber-9);
  @supports (color: color(display-p3 1 1 1)) {
    @media (color-gamut: p3) {
      --amber-surface: color(display-p3 0.1412 0.1176 0.0784 / 0.5);
    }
  }
  @supports (color: color-mix(in oklab, white, black)) {
    --amber-track: color-mix(in oklab, var(--amber-8), var(--amber-9) 75%);
  }
}

@import '@radix-ui/colors/crimson.css';
@import '@radix-ui/colors/crimson-dark.css';
@import '@radix-ui/colors/crimson-alpha.css';
@import '@radix-ui/colors/crimson-dark-alpha.css';

:root {
  --crimson-contrast: white;
}

:root,
.light,
.light-theme {
  --crimson-surface: #fef5f8cc;
  --crimson-indicator: var(--crimson-9);
  --crimson-track: var(--crimson-9);
  @supports (color: color(display-p3 1 1 1)) {
    @media (color-gamut: p3) {
      --crimson-surface: color(display-p3 0.9922 0.9608 0.9725 / 0.8);
    }
  }
}

.dark,
.dark-theme {
  --crimson-surface: #2f151f80;
  --crimson-indicator: var(--crimson-9);
  --crimson-track: var(--crimson-9);
  @supports (color: color(display-p3 1 1 1)) {
    @media (color-gamut: p3) {
      --crimson-surface: color(display-p3 0.1647 0.0863 0.1176 / 0.5);
    }
  }
}

@import '@radix-ui/colors/lime.css';
@import '@radix-ui/colors/lime-dark.css';
@import '@radix-ui/colors/lime-alpha.css';
@import '@radix-ui/colors/lime-dark-alpha.css';

:root {
  --lime-contrast: #1d211c; /* light mode olive 12 */
}

:root,
.light,
.light-theme {
  --lime-surface: #f6f9f0cc;
  --lime-indicator: var(--lime-9);
  --lime-track: var(--lime-9);
  @supports (color: color(display-p3 1 1 1)) {
    @media (color-gamut: p3) {
      --lime-surface: color(display-p3 0.9725 0.9765 0.9412 / 0.8);
    }
  }
}

.dark,
.dark-theme {
  --lime-surface: #1b211580;
